/**
 * Build a payload and deliver it through all specified channels.
 * Checks user preferences before sending (if PreferencesService is set).
 */
private async sendNotification(params: {
  type: NotificationType;
  channels: NotificationChannel[];
  priority: NotificationPriority;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  userId?: string;
}): Promise<void> {
  // Check user preferences before sending (per-channel filtering)
  if (this.preferencesService && params.userId) {
    const channels = params.channels.filter((channel) => {
      return this.preferencesService!.shouldSend(params.userId!, channel, params.type);
    });

    if (channels.length === 0) {
      this.logger.info(
        `Notification suppressed by user preferences: user=${params.userId}, type=${params.type}`,
      );
      return;
    }

    params = { ...params, channels };
  }

  const payload: NotificationPayload = {
    id: generateNotificationId(),
    type: params.type,
    channels: params.channels,
    priority: params.priority,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    metadata: params.metadata,
    createdAt: new Date(),
  };

  for (const channel of payload.channels) {
    const adapter = this.adapters.get(channel);
    let result: DeliveryResult;

    if (!adapter) {
      this.logger.warn(`No adapter registered for channel: ${channel}`);
      result = { success: false, error: `No adapter for channel: ${channel}` };
    } else {
      result = await adapter.send(payload);
    }

    const record: NotificationRecord = {
      ...payload,
      deliveredVia: channel,
      success: result.success,
      error: result.error,
      deliveredAt: new Date(),
    };
    this.records.push(record);

    if (this.historyService) {
      this.historyService.log(record);
    }

    if (result.success) {
      this.logger.info(`Notification ${payload.id} delivered via ${channel}`);
    } else {
      this.logger.error(
        `Notification ${payload.id} failed via ${channel}: ${result.error}`,
      );
    }
  }
}

